        var result = _viarecebimentoReader.ReadAll(dbRec, _mockDataRecord.Object);
        // Assert
        result.Should().NotBeNull();
        result.Should().BeOfType<ViaRecebimentoResponseAll>();
        result!.Id.Should().Be(testId);
        result.Nome.Should().Be(testNome);
